3_real_world_example.code:
const jsonString = '{"name": "Alice", bad json}';

try {
  const user = JSON.parse(jsonString);
  console.log('Parsed successfully:', user);
} catch (error) {
  console.error('Failed to parse user data!');
  console.error(error.message); // Unexpected token b in JSON at position 18
} finally {
  console.log('Finished processing request.');
}

